import { InView } from 'react-intersection-observer';
import styled from "styled-components"
import SectionHeader from './SectionHeader'

const Projects = ({ id }) => {
  return (
    <ProjectsContainer id={id}>
      <InView triggerOnce>
        {({ inView, ref, entry }) => (
          <SectionHeader inView={inView} ref={ref} />
        )}
      </InView>

      <ProjectsList>
        <Project>
          <h4> Vans Scrapper Website </h4>
          <ul>
            <li> React </li>
            <li> React Redux </li>
            <li> Express </li>
            <li> Mongoose </li>
            <li> Styled Components </li>
            <li> Puppeteer </li>
          </ul>
          <span> Description </span>
        </Project>
        <Project>
          <h4> Tibia Object Builder </h4>
          <ul>
            <li> React </li>
            <li> React Redux </li>
            <li> Styled Components </li>
          </ul>
          <span> Description </span>
        </Project>
      </ProjectsList>
    </ProjectsContainer>
  )
}

const ProjectsContainer = styled.section`
  width: 100%;
  height: 100vh;

  color: white;
  /* font-size: 3em; */
`

const ProjectsList = styled.ul`
  margin-top: 5em;
  display: flex;
  flex-direction: column;
  padding-left: 15em;
  row-gap: 3em;
`

const Project = styled.li`
  & ul {
    padding: 0;
    display: flex;
    column-gap: 2em;
    letter-spacing: 1px;
  }

  & h4 {
    margin: 0;
    font-size: 4em;
  }
`

export default Projects
